'use client';

/**
 * Hook para gerenciar labels/tags do WhatsApp
 * @module hooks/useWhatsAppLabels
 */

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { useUserProfile } from '@/hooks/useUserProfile';
import { toast } from '@/hooks/use-toast';
import type {
    WhatsAppLabel,
    WhatsAppLabelInsert,
    WhatsAppLabelUpdate,
} from '@/types/whatsapp';

// Query keys
export const WHATSAPP_LABELS_KEY = 'whatsapp-labels';

export function useWhatsAppLabels() {
    const supabase = createClient();
    const queryClient = useQueryClient();
    const { user } = useAuth();
    const { profile } = useUserProfile();

    // =========================================
    // Query: Lista de labels
    // =========================================
    const labelsQuery = useQuery({
        queryKey: [WHATSAPP_LABELS_KEY],
        queryFn: async (): Promise<WhatsAppLabel[]> => {
            if (!user?.id) return [];

            const { data, error } = await supabase
                .from('whatsapp_conversation_labels')
                .select('*')
                .order('name', { ascending: true });

            if (error) {
                console.error('[useWhatsAppLabels] Error:', error);
                throw error;
            }

            return (data || []) as WhatsAppLabel[];
        },
        enabled: !!user?.id,
    });

    // =========================================
    // Mutation: Criar label
    // =========================================
    const createLabelMutation = useMutation({
        mutationFn: async (payload: Omit<WhatsAppLabelInsert, 'user_id' | 'organization_id'>): Promise<WhatsAppLabel> => {
            if (!user?.id) throw new Error('Usuário não autenticado');

            const { data, error } = await supabase
                .from('whatsapp_conversation_labels')
                .insert({
                    ...payload,
                    user_id: user.id,
                    organization_id: profile?.organization_id,
                } as never)
                .select()
                .single();

            if (error) throw error;
            return data as WhatsAppLabel;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [WHATSAPP_LABELS_KEY] });
            toast({
                title: 'Marcador criado',
            });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao criar marcador',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Mutation: Atualizar label
    // =========================================
    const updateLabelMutation = useMutation({
        mutationFn: async ({
            labelId,
            updates,
        }: {
            labelId: string;
            updates: WhatsAppLabelUpdate;
        }): Promise<WhatsAppLabel> => {
            const { data, error } = await supabase
                .from('whatsapp_conversation_labels')
                .update(updates as never)
                .eq('id', labelId)
                .select()
                .single();

            if (error) throw error;
            return data as WhatsAppLabel;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [WHATSAPP_LABELS_KEY] });
            toast({
                title: 'Marcador atualizado',
            });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao atualizar marcador',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Mutation: Deletar label
    // =========================================
    const deleteLabelMutation = useMutation({
        mutationFn: async (labelId: string): Promise<void> => {
            const { error } = await supabase
                .from('whatsapp_conversation_labels')
                .delete()
                .eq('id', labelId);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [WHATSAPP_LABELS_KEY] });
            toast({
                title: 'Marcador removido',
            });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao remover marcador',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Mutation: Atribuir label a conversa
    // =========================================
    const assignLabelMutation = useMutation({
        mutationFn: async ({
            conversationId,
            labelId,
        }: {
            conversationId: string;
            labelId: string;
        }): Promise<void> => {
            const { error } = await supabase
                .from('whatsapp_conversation_label_assignments')
                .insert({
                    conversation_id: conversationId,
                    label_id: labelId,
                } as never);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['whatsapp-conversations'] });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao atribuir marcador',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Mutation: Remover label de conversa
    // =========================================
    const removeLabelMutation = useMutation({
        mutationFn: async ({
            conversationId,
            labelId,
        }: {
            conversationId: string;
            labelId: string;
        }): Promise<void> => {
            const { error } = await supabase
                .from('whatsapp_conversation_label_assignments')
                .delete()
                .eq('conversation_id', conversationId)
                .eq('label_id', labelId);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['whatsapp-conversations'] });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao remover marcador',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    return {
        // Data
        labels: labelsQuery.data || [],
        isLoading: labelsQuery.isLoading,
        error: labelsQuery.error,

        // Mutations
        createLabel: createLabelMutation.mutateAsync,
        isCreating: createLabelMutation.isPending,

        updateLabel: updateLabelMutation.mutateAsync,
        isUpdating: updateLabelMutation.isPending,

        deleteLabel: deleteLabelMutation.mutateAsync,
        isDeleting: deleteLabelMutation.isPending,

        assignLabel: assignLabelMutation.mutateAsync,
        isAssigning: assignLabelMutation.isPending,

        removeLabel: removeLabelMutation.mutateAsync,
        isRemoving: removeLabelMutation.isPending,
    };
}
